contracts/EHRAccessControl.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

contract EHRAccessControl is AccessControl {
    bytes32 public constant BACKEND_ROLE = keccak256("BACKEND_ROLE");

    enum AccessStatus {
        NONE,
        REQUESTED,
        GRANTED,
        DENIED,
        REVOKED
    }

    struct AccessGrant {
        AccessStatus status;
        uint256 timestamp;
        string ipfsCID;
        bytes32 dataHash;
    }

    // UPDATED: Enhanced access log with patient and doctor IDs
    struct AccessLog {
        uint256 patientId;
        uint256 doctorId;
        AccessStatus status;
        uint256 timestamp;
        string ipfsCID;
        bytes32 dataHash;
    }

    // accessGrants is public which creates a getter function automatically
    mapping(uint256 patientId => mapping(uint256 doctorId => AccessGrant))
        public accessGrants;

    // UPDATED: Global access history array
    AccessLog[] private globalAccessHistory;

    event AccessRequested(
        uint256 indexed patientId,
        uint256 indexed doctorId,
        uint256 timestamp
    );
    event AccessGranted(
        uint256 indexed patientId,
        uint256 indexed doctorId,
        string ipfsCID,
        bytes32 dataHash,
        uint256 timestamp
    );
    event AccessDenied(
        uint256 indexed patientId,
        uint256 indexed doctorId,
        uint256 timestamp
    );
    event AccessRevoked(
        uint256 indexed patientId,
        uint256 indexed doctorId,
        uint256 timestamp
    );

    constructor(address backendAddress) {
        require(backendAddress != address(0), "Invalid backend address");

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(BACKEND_ROLE, backendAddress);
    }

    modifier onlyBackend() {
        require(
            hasRole(BACKEND_ROLE, msg.sender),
            "Unauthorized: BACKEND_ROLE required"
        );
        _;
    }

    // UPDATED: Allow re-requesting after DENIED status
    function requestAccess(
        uint256 patientId,
        uint256 doctorId
    ) external onlyBackend {
        AccessStatus currentStatus = accessGrants[patientId][doctorId].status;

        require(
            currentStatus == AccessStatus.NONE ||
                currentStatus == AccessStatus.DENIED,
            "Invalid status for request"
        );

        accessGrants[patientId][doctorId] = AccessGrant({
            status: AccessStatus.REQUESTED,
            timestamp: block.timestamp,
            ipfsCID: "",
            dataHash: bytes32(0)
        });

        // Log the request
        _addAccessLog(
            patientId,
            doctorId,
            AccessStatus.REQUESTED,
            "",
            bytes32(0)
        );

        emit AccessRequested(patientId, doctorId, block.timestamp);
    }

    // UPDATED: Allow re-granting from REVOKED status
    function grantAccess(
        uint256 patientId,
        uint256 doctorId,
        string calldata ipfsCID,
        bytes32 dataHash
    ) external onlyBackend {
        AccessStatus currentStatus = accessGrants[patientId][doctorId].status;

        require(
            currentStatus == AccessStatus.REQUESTED ||
                currentStatus == AccessStatus.REVOKED,
            "Invalid status transition"
        );

        accessGrants[patientId][doctorId] = AccessGrant({
            status: AccessStatus.GRANTED,
            timestamp: block.timestamp,
            ipfsCID: ipfsCID,
            dataHash: dataHash
        });

        // Log the grant
        _addAccessLog(
            patientId,
            doctorId,
            AccessStatus.GRANTED,
            ipfsCID,
            dataHash
        );

        emit AccessGranted(
            patientId,
            doctorId,
            ipfsCID,
            dataHash,
            block.timestamp
        );
    }

    function denyAccess(
        uint256 patientId,
        uint256 doctorId
    ) external onlyBackend {
        require(
            accessGrants[patientId][doctorId].status == AccessStatus.REQUESTED,
            "Invalid status transition"
        );

        accessGrants[patientId][doctorId].status = AccessStatus.DENIED;
        accessGrants[patientId][doctorId].timestamp = block.timestamp;

        // Log the denial
        _addAccessLog(patientId, doctorId, AccessStatus.DENIED, "", bytes32(0));

        emit AccessDenied(patientId, doctorId, block.timestamp);
    }

    function revokeAccess(
        uint256 patientId,
        uint256 doctorId
    ) external onlyBackend {
        require(
            accessGrants[patientId][doctorId].status == AccessStatus.GRANTED,
            "Invalid status transition"
        );

        accessGrants[patientId][doctorId].status = AccessStatus.REVOKED;
        accessGrants[patientId][doctorId].timestamp = block.timestamp;

        // Log the revocation
        _addAccessLog(
            patientId,
            doctorId,
            AccessStatus.REVOKED,
            accessGrants[patientId][doctorId].ipfsCID,
            accessGrants[patientId][doctorId].dataHash
        );

        emit AccessRevoked(patientId, doctorId, block.timestamp);
    }

    // Get complete global access history
    function getAccessHistory()
        external
        view
        onlyBackend
        returns (AccessLog[] memory)
    {
        return globalAccessHistory;
    }

    // NEW: Get total count of access logs
    function getAccessHistoryCount()
        external
        view
        onlyBackend
        returns (uint256)
    {
        return globalAccessHistory.length;
    }

    // NEW: Get paginated access history
    function getAccessHistoryPaginated(
        uint256 offset,
        uint256 limit
    ) external view onlyBackend returns (AccessLog[] memory) {
        uint256 total = globalAccessHistory.length;

        if (offset >= total) {
            return new AccessLog[](0);
        }

        uint256 end = offset + limit;
        if (end > total) {
            end = total;
        }

        uint256 size = end - offset;
        AccessLog[] memory result = new AccessLog[](size);

        for (uint256 i = 0; i < size; i++) {
            result[i] = globalAccessHistory[offset + i];
        }

        return result;
    }

    // PRIVATE: Helper function to log access changes to global history
    function _addAccessLog(
        uint256 patientId,
        uint256 doctorId,
        AccessStatus status,
        string memory ipfsCID,
        bytes32 dataHash
    ) private {
        globalAccessHistory.push(
            AccessLog({
                patientId: patientId,
                doctorId: doctorId,
                status: status,
                timestamp: block.timestamp,
                ipfsCID: ipfsCID,
                dataHash: dataHash
            })
        );
    }
}

contracts/EHRProof.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;
//import "hardhat/console.sol"; for debugging
import "@openzeppelin/contracts/access/AccessControl.sol";

contract EHRProof is AccessControl {
    bytes32 public constant BACKEND_ROLE = keccak256("BACKEND_ROLE");

    struct Proof {
        address submitter;
        string patientId;
        string cid; // IPFS CID
        bytes32 dataHash; // SHA-256 hash of canonical JSON (not the CID)
        uint256 timestamp;
    }

    mapping(bytes32 => Proof) public proofs; // proofId => Proof
    mapping(string => bytes32) public patientProofIds; // patientId => proofId

    event ProofRecorded(
        bytes32 indexed proofId,
        string indexed patientId,
        string cid,
        bytes32 dataHash,
        address indexed submitter,
        uint256 timestamp
    );

    constructor(address backendSigner) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        if (backendSigner != address(0)) {
            _grantRole(BACKEND_ROLE, backendSigner);
        }
    }

    function computeProofId(
        string memory patientId,
        string memory cid,
        bytes32 dataHash
    ) public pure returns (bytes32) {
        return keccak256(abi.encodePacked(patientId, "|", cid, "|", dataHash));
    }

    function recordPatientProof(
        string calldata patientId,
        string calldata cid,
        bytes32 dataHash
    ) external onlyRole(BACKEND_ROLE) returns (bytes32 proofId) {
        proofId = computeProofId(patientId, cid, dataHash);
        require(proofs[proofId].timestamp == 0, "Proof exists");

        proofs[proofId] = Proof({
            submitter: msg.sender,
            patientId: patientId,
            cid: cid,
            dataHash: dataHash,
            timestamp: block.timestamp
        });

        patientProofIds[patientId] = proofId;

        emit ProofRecorded(
            proofId,
            patientId,
            cid,
            dataHash,
            msg.sender,
            block.timestamp
        );
    }

    function getProof(
        string calldata patientId
    )
        external
        view
        returns (
            bool exists,
            string memory cid,
            bytes32 dataHash,
            uint256 timestamp,
            address submitter
        )
    {
        bytes32 proofId = patientProofIds[patientId];

        if (proofId == bytes32(0)) {
            return (false, "", bytes32(0), 0, address(0));
        }

        Proof memory proof = proofs[proofId];

        if (proof.timestamp == 0) {
            return (false, "", bytes32(0), 0, address(0));
        }

        return (
            true,
            proof.cid,
            proof.dataHash,
            proof.timestamp,
            proof.submitter
        );
    }
}

contracts/Payment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Payment {
    mapping(address => uint) public patientPayments;
    mapping(address => uint) public insurancePayments;
    mapping(uint => address) public hospitalById; // Map hospital ID to address
    mapping(address => bool) public validHospitals;
    address public admin;

    // Transaction history structures
    struct Transaction {
        address from;
        address to;
        uint amount;
        uint256 timestamp;
        string transactionType; // "PATIENT" or "INSURANCE"
        uint256 claimId; // Added claim ID
    }

    // Patient transaction history
    mapping(address => Transaction[]) public patientTransactionHistory;

    // Insurance transaction history
    mapping(address => Transaction[]) public insuranceTransactionHistory;

    // Hospital received payments history
    mapping(address => Transaction[]) public hospitalReceivedHistory;

    event PatientTransfer(
        address indexed from,
        address indexed to,
        uint amount,
        uint256 timestamp,
        uint256 claimId
    );
    event InsuranceTransfer(
        address indexed from,
        address indexed to,
        uint amount,
        uint256 timestamp,
        uint256 claimId
    );
    event HospitalRegistered(uint indexed hospitalId, address indexed hospital);
    event HospitalUpdated(
        uint indexed hospitalId,
        address indexed oldAddress,
        address indexed newAddress
    );

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin");
        _;
    }

    // Register or update hospital by ID
    function registerHospital(
        uint hospitalId,
        address hospital
    ) external onlyAdmin {
        require(hospital != address(0), "Invalid hospital address");

        address oldAddress = hospitalById[hospitalId];

        if (oldAddress != address(0)) {
            // Update existing hospital
            validHospitals[oldAddress] = false; // Invalidate old address
            emit HospitalUpdated(hospitalId, oldAddress, hospital);
        } else {
            // New hospital registration
            emit HospitalRegistered(hospitalId, hospital);
        }

        hospitalById[hospitalId] = hospital;
        validHospitals[hospital] = true;
    }

    // Get hospital address by ID
    function getHospitalAddress(
        uint hospitalId
    ) external view returns (address) {
        return hospitalById[hospitalId];
    }

    function transferFromPatient(
        address from,
        address to,
        uint amount,
        uint256 claimId
    ) external payable {
        require(validHospitals[to], "Invalid hospital");
        require(msg.value == amount, "Incorrect amount");
        payable(to).transfer(amount);
        patientPayments[from] += amount;

        // Store transaction in patient history
        Transaction memory txn = Transaction({
            from: from,
            to: to,
            amount: amount,
            timestamp: block.timestamp,
            transactionType: "PATIENT",
            claimId: claimId
        });

        patientTransactionHistory[from].push(txn);
        hospitalReceivedHistory[to].push(txn);

        emit PatientTransfer(from, to, amount, block.timestamp, claimId);
    }

    function transferFromInsurance(
        address from,
        address to,
        uint amount,
        uint256 claimId
    ) external payable {
        require(validHospitals[to], "Invalid hospital");
        require(msg.value == amount, "Incorrect amount");
        payable(to).transfer(amount);
        insurancePayments[from] += amount;

        // Store transaction in insurance history
        Transaction memory txn = Transaction({
            from: from,
            to: to,
            amount: amount,
            timestamp: block.timestamp,
            transactionType: "INSURANCE",
            claimId: claimId
        });

        insuranceTransactionHistory[from].push(txn);
        hospitalReceivedHistory[to].push(txn);

        emit InsuranceTransfer(from, to, amount, block.timestamp, claimId);
    }

    // Get wallet balance
    function getWalletBalance(address wallet) external view returns (uint256) {
        return wallet.balance;
    }

    // Get patient payment total
    function getPatientPaymentTotal(
        address patient
    ) external view returns (uint256) {
        return patientPayments[patient];
    }

    // Get insurance payment total
    function getInsurancePaymentTotal(
        address insurance
    ) external view returns (uint256) {
        return insurancePayments[insurance];
    }

    // Get patient transaction history
    function getPatientTransactionHistory(
        address patient
    ) external view returns (Transaction[] memory) {
        return patientTransactionHistory[patient];
    }

    // Get insurance transaction history
    function getInsuranceTransactionHistory(
        address insurance
    ) external view returns (Transaction[] memory) {
        return insuranceTransactionHistory[insurance];
    }

    // Get hospital received payment history
    function getHospitalReceivedHistory(
        address hospital
    ) external view returns (Transaction[] memory) {
        return hospitalReceivedHistory[hospital];
    }

    // Get patient transaction count
    function getPatientTransactionCount(
        address patient
    ) external view returns (uint256) {
        return patientTransactionHistory[patient].length;
    }

    // Get insurance transaction count
    function getInsuranceTransactionCount(
        address insurance
    ) external view returns (uint256) {
        return insuranceTransactionHistory[insurance].length;
    }

    // Get hospital received transaction count
    function getHospitalReceivedCount(
        address hospital
    ) external view returns (uint256) {
        return hospitalReceivedHistory[hospital].length;
    }
}

